(function() {
    'use strict';

    const TH = window.TavernHelper;
    if (!TH) {
        console.warn('[最小脚本] 未检测到 JS-Slash-Runner / TavernHelper');
        return;
    }

    function notify(message, type = 'info') {
        if (window.toastr && typeof window.toastr[type] === 'function') {
            window.toastr[type](message, '最小脚本');
        } else {
            console.log('[最小脚本]', message);
        }
    }

    async function main() {
        const lastId = typeof TH.getLastMessageId === 'function' ? TH.getLastMessageId() : 0;
        const messages = typeof TH.getChatMessages === 'function'
            ? TH.getChatMessages(`0-${lastId}`, { include_swipes: false })
            : [];

        notify(`读取到 ${messages.length} 条消息`);
    }

    main().catch(error => {
        console.error('[最小脚本] 运行失败:', error);
        notify(error.message || String(error), 'error');
    });
})();
